import api from './api';

// Create a booking
export const createBooking = async (bookingData) => {
  const response = await api.post('/bookings', bookingData);
  return response.data;
};

// Get user's bookings (backend filters by auth user)
export const getMyBookings = async () => {
  const response = await api.get('/bookings');
  return response.data;
};

// Cancel booking (uses DELETE, not PUT)
export const cancelBooking = async (id) => {
  const response = await api.delete(`/bookings/${id}`);
  return response.data;
};

// Get booked dates for a specific room (for calendar display)
// Returns array of dates: ["2026-04-19", "2026-04-20", ...]
export const getRoomBookedDates = async (roomId, year, month) => {
  const response = await api.get(`/bookings/room/${roomId}/dates?year=${year}&month=${month}`);
  return response.data;
};

export default { createBooking, getMyBookings, cancelBooking, getRoomBookedDates };
